                    withPattern: `// Implementation hierarchy
interface Renderer {
    void renderCircle(double radius);
    void renderSquare(double side);
}

class VectorRenderer implements Renderer {
    @Override
    public void renderCircle(double radius) {
        System.out.println("Drawing circle (radius=" + radius + ") as vector");
    }
    @Override
    public void renderSquare(double side) {
        System.out.println("Drawing square (side=" + side + ") as vector");
    }
}

class RasterRenderer implements Renderer {
    @Override
    public void renderCircle(double radius) {
        System.out.println("Drawing " + (int)(Math.PI * radius * radius)
            + " pixels for circle (radius=" + radius + ")");
    }
    @Override
    public void renderSquare(double side) {
        System.out.println("Drawing " + (int)(side * side)
            + " pixels for square (side=" + side + ")");
    }
}

// Abstraction hierarchy
abstract class Shape {
    protected Renderer renderer; // Bridge

    public Shape(Renderer renderer) {
        this.renderer = renderer;
    }

    public abstract void draw();
    public abstract void resize(double factor);
}

class Circle extends Shape {
    private double radius;

    public Circle(Renderer renderer, double radius) {
        super(renderer);
        this.radius = radius;
    }

    @Override public void draw()                    { renderer.renderCircle(radius); }
    @Override public void resize(double factor)     { radius *= factor; }
}

class Square extends Shape {
    private double side;

    public Square(Renderer renderer, double side) {
        super(renderer);
        this.side = side;
    }

    @Override public void draw()                    { renderer.renderSquare(side); }
    @Override public void resize(double factor)     { side *= factor; }
}

public class Main {
    public static void main(String[] args) {
        Shape c = new Circle(new VectorRenderer(), 5);
        Shape s = new Square(new RasterRenderer(), 4);

        c.draw();
        s.draw();
        c.resize(2);
        c.draw();
    }
}`,
