                    withPattern: `// Strategy interface
interface GradingStrategy {
    String grade(double score, double maxScore);
}

// Concrete strategies
class PercentageGrading implements GradingStrategy {
    @Override
    public String grade(double score, double maxScore) {
        double pct = (score / maxScore) * 100;
        if (pct >= 80) return "A (" + (int)pct + "%)";
        if (pct >= 60) return "B (" + (int)pct + "%)";
        if (pct >= 40) return "C (" + (int)pct + "%)";
        return "F (" + (int)pct + "%)";
    }
}

class PassFailGrading implements GradingStrategy {
    private double threshold;
    public PassFailGrading(double threshold) {
        this.threshold = threshold;
    }

    @Override
    public String grade(double score, double maxScore) {
        return score >= threshold ? "PASS" : "FAIL";
    }
}

class CurvedGrading implements GradingStrategy {
    private double curveBonus;
    public CurvedGrading(double curveBonus) {
        this.curveBonus = curveBonus;
    }

    @Override
    public String grade(double score, double maxScore) {
        double adjusted = Math.min(score + curveBonus, maxScore);
        double pct = (adjusted / maxScore) * 100;
        return "A (curved: " + (int)pct + "%)";
    }
}

// Context
class ExamResult {
    private String studentName;
    private double score;
    private double maxScore;
    private GradingStrategy strategy;

    public ExamResult(String name, double score, double max) {
        this.studentName = name;
        this.score       = score;
        this.maxScore    = max;
    }

    public void setStrategy(GradingStrategy strategy) {
        this.strategy = strategy;
    }

    public void printGrade() {
        System.out.println(studentName + ": "
            + strategy.grade(score, maxScore));
    }
}

public class Main {
    public static void main(String[] args) {
        ExamResult result = new ExamResult("Afif", 72, 100);

        result.setStrategy(new PercentageGrading());
        result.printGrade();

        result.setStrategy(new PassFailGrading(50));
        result.printGrade();

        result.setStrategy(new CurvedGrading(10));
        result.printGrade();
    }
}`,
