                    desc: "A bank queues and executes transactions. Some fail — need to rollback. Command encapsulates each transaction and supports rollback.",
                    withPattern: `import java.util.ArrayDeque;
import java.util.Queue;
import java.util.Stack;

interface BankCommand {
    boolean execute();
    void rollback();
    String getDescription();
}

class Account {
    private String id;
    private double balance;
    public Account(String id, double balance) { this.id=id; this.balance=balance; }
    public boolean debit(double amt)  { if (balance>=amt) { balance-=amt; return true; } return false; }
    public void credit(double amt)    { balance += amt; }
    public double getBalance()        { return balance; }
    public String getId()             { return id; }
}

class TransferCommand implements BankCommand {
    private Account from, to;
    private double amount;
    private boolean executed = false;

    public TransferCommand(Account from, Account to, double amount) {
        this.from = from; this.to = to; this.amount = amount;
    }

    @Override
    public boolean execute() {
        if (from.debit(amount)) {
            to.credit(amount);
            executed = true;
            System.out.printf("[OK] Transferred $%.2f from %s to %s%n",
                amount, from.getId(), to.getId());
            return true;
        }
        System.out.printf("[FAIL] Insufficient funds in %s%n", from.getId());
        return false;
    }

    @Override
    public void rollback() {
        if (executed) {
            to.debit(amount);
            from.credit(amount);
            System.out.printf("[ROLLBACK] Reversed $%.2f transfer%n", amount);
        }
    }

    @Override public String getDescription() {
        return "Transfer $" + amount + " from " + from.getId() + " to " + to.getId();
    }
}

class TransactionProcessor {
    private Queue<BankCommand> queue = new ArrayDeque<>();
    private Stack<BankCommand> done  = new Stack<>();

    public void queue(BankCommand cmd) { queue.add(cmd); }

    public void processAll() {
        while (!queue.isEmpty()) {
            BankCommand cmd = queue.poll();
            if (cmd.execute()) {
                done.push(cmd);
            }
        }
    }

    public void rollbackLast() {
        if (!done.isEmpty()) done.pop().rollback();
    }
}

public class Main {
    public static void main(String[] args) {
        Account a = new Account("ACC-001", 5000);
        Account b = new Account("ACC-002", 1000);

        TransactionProcessor processor = new TransactionProcessor();
        processor.queue(new TransferCommand(a, b, 2000));
        processor.queue(new TransferCommand(b, a, 9999)); // will fail — insufficient
        processor.queue(new TransferCommand(a, b, 500));

        processor.processAll();
        System.out.printf("ACC-001: $%.2f | ACC-002: $%.2f%n",
            a.getBalance(), b.getBalance());

        processor.rollbackLast();
        System.out.printf("After rollback → ACC-001: $%.2f | ACC-002: $%.2f%n",
            a.getBalance(), b.getBalance());
    }
}`,
