                    desc: "A bank account has transaction history. An Iterator lets auditors traverse forward or backward without knowing if it's stored in an array, list, or linked list.",
                    withPattern: `import java.util.ArrayList;
import java.util.List;

class Transaction {
    private String type;
    private double amount;
    private String date;

    public Transaction(String type, double amount, String date) {
        this.type = type; this.amount = amount; this.date = date;
    }

    @Override
    public String toString() {
        return String.format("%-12s $%8.2f  (%s)", type, amount, date);
    }
}

interface TransactionIterator {
    boolean hasNext();
    boolean hasPrev();
    Transaction next();
    Transaction prev();
}

class TransactionHistory {
    private List<Transaction> records = new ArrayList<>();

    public void add(Transaction t) { records.add(t); }

    public TransactionIterator forwardIterator() {
        return new BiDirectionalIterator(records, false);
    }

    public TransactionIterator reverseIterator() {
        return new BiDirectionalIterator(records, true);
    }
}

class BiDirectionalIterator implements TransactionIterator {
    private List<Transaction> list;
    private int index;

    public BiDirectionalIterator(List<Transaction> list, boolean reverse) {
        this.list = list;
        this.index = reverse ? list.size() - 1 : 0;
    }

    @Override public boolean hasNext() { return index < list.size(); }
    @Override public boolean hasPrev() { return index >= 0; }
    @Override public Transaction next() { return list.get(index++); }
    @Override public Transaction prev() { return list.get(index--); }
}

public class Main {
    public static void main(String[] args) {
        TransactionHistory history = new TransactionHistory();
        history.add(new Transaction("DEPOSIT",    5000, "2025-01-01"));
        history.add(new Transaction("WITHDRAWAL", 1200, "2025-01-05"));
        history.add(new Transaction("TRANSFER",   3000, "2025-01-10"));
        history.add(new Transaction("DEPOSIT",    2000, "2025-01-15"));

        System.out.println("Forward (oldest first):");
        TransactionIterator it = history.forwardIterator();
        while (it.hasNext()) System.out.println("  " + it.next());

        System.out.println("Reverse (newest first):");
        it = history.reverseIterator();
        while (it.hasPrev()) System.out.println("  " + it.prev());
    }
}`,
