                    withPattern: `// Handler interface
abstract class ComplaintHandler {
    protected ComplaintHandler next;

    public ComplaintHandler setNext(ComplaintHandler next) {
        this.next = next;
        return next; // allows chaining
    }

    public abstract void handle(String complaint, int severity);
}

// Concrete Handlers
class ClassTeacher extends ComplaintHandler {
    private String name;
    public ClassTeacher(String name) { this.name = name; }

    @Override
    public void handle(String complaint, int severity) {
        if (severity <= 2) {
            System.out.println("[Class Teacher " + name
                + "] Handled: " + complaint);
        } else if (next != null) {
            System.out.println("[Class Teacher " + name
                + "] Escalating severity " + severity + " to dept. head...");
            next.handle(complaint, severity);
        }
    }
}

class DepartmentHead extends ComplaintHandler {
    private String dept;
    public DepartmentHead(String dept) { this.dept = dept; }

    @Override
    public void handle(String complaint, int severity) {
        if (severity <= 4) {
            System.out.println("[" + dept + " Dept Head] Handled: " + complaint);
        } else if (next != null) {
            System.out.println("[" + dept
                + " Dept Head] Too serious — escalating to Principal...");
            next.handle(complaint, severity);
        }
    }
}

class Principal extends ComplaintHandler {
    @Override
    public void handle(String complaint, int severity) {
        System.out.println("[PRINCIPAL] Handling serious complaint (severity "
            + severity + "): " + complaint);
    }
}

public class Main {
    public static void main(String[] args) {
        // Build the chain
        ComplaintHandler teacher = new ClassTeacher("Mr. Karim");
        ComplaintHandler deptHead = new DepartmentHead("Science");
        ComplaintHandler principal = new Principal();

        teacher.setNext(deptHead).setNext(principal);

        teacher.handle("Lost textbook", 1);
        teacher.handle("Classroom bully", 3);
        teacher.handle("Exam fraud allegation", 5);
    }
}`,
