                    title: "Bank Account Snapshot",
                    desc: "Before a risky operation (like bulk withdrawal), save a snapshot. If the operation fails, roll back to the saved state.",
                    withPattern: `import java.util.Stack;

class AccountMemento {
    private final double balance;
    private final String lastTransaction;

    public AccountMemento(double balance, String lastTransaction) {
        this.balance         = balance;
        this.lastTransaction = lastTransaction;
    }

    double getBalance()           { return balance; }
    String getLastTransaction()   { return lastTransaction; }
}

class BankAccount {
    private String accountId;
    private double balance;
    private String lastTransaction = "None";

    public BankAccount(String id, double balance) {
        this.accountId = id;
        this.balance   = balance;
    }

    public void deposit(double amount) {
        balance += amount;
        lastTransaction = "Deposit $" + amount;
        System.out.printf("[%s] Deposit: $%.2f | Balance: $%.2f%n",
            accountId, amount, balance);
    }

    public boolean withdraw(double amount) {
        if (balance < amount) {
            System.out.println("[" + accountId + "] Insufficient funds!");
            return false;
        }
        balance -= amount;
        lastTransaction = "Withdrawal $" + amount;
        System.out.printf("[%s] Withdrawal: $%.2f | Balance: $%.2f%n",
            accountId, amount, balance);
        return true;
    }

    public AccountMemento save() {
        return new AccountMemento(balance, lastTransaction);
    }

    public void restore(AccountMemento m) {
        this.balance         = m.getBalance();
        this.lastTransaction = m.getLastTransaction();
        System.out.printf("[%s] Restored → Balance: $%.2f | Last: %s%n",
            accountId, balance, lastTransaction);
    }

    public double getBalance() { return balance; }
}

class AccountHistory {
    private Stack<AccountMemento> history = new Stack<>();
    public void save(AccountMemento m)    { history.push(m); }
    public AccountMemento rollback()      {
        return history.isEmpty() ? null : history.pop();
    }
}

public class Main {
    public static void main(String[] args) {
        BankAccount acc     = new BankAccount("ACC-001", 10000);
        AccountHistory hist = new AccountHistory();

        acc.deposit(2000);

        // Save before risky operation
        hist.save(acc.save());
        System.out.println("Checkpoint saved.");

        acc.withdraw(8000);
        acc.withdraw(5000); // will fail

        System.out.println("\n--- Rolling back to checkpoint ---");
        acc.restore(hist.rollback());
    }
}`,
